import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

import ScrollReveal from "@/components/feedback/ScrollReveal";
import { env } from "@/config/env";
import { useContract, useCreatorOnboardingCta } from "@/hooks";

const CTASection: React.FC = () => {
  const [totalCreators, setTotalCreators] = useState<number>(0);
  const { getStats } = useContract();
  const { connected, isRegistered, profileHref, openWalletConnect } =
    useCreatorOnboardingCta();

  useEffect(() => {
    if (!env.contractConfigured) return;
    getStats()
      .then((stats) => setTotalCreators(stats.totalCreators))
      .catch(() => {});
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const scrollToThreeWays = () => {
    document.getElementById("three-ways")?.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <section className="editorial-section border-t border-zap-border bg-zap-bg-alt">
      <div className="editorial-container">
        <ScrollReveal>
          <div className="mx-auto max-w-3xl text-center">
            <h2 className="font-body text-[clamp(2.25rem,5vw,3.5rem)] font-normal leading-[1.05] text-zap-ink">
              Make money doing what you love
            </h2>
            <p className="mx-auto mt-5 max-w-xl font-body text-base leading-relaxed text-zap-ink-muted">
              {totalCreators > 0 ? (
                <>
                  <span className="font-semibold tabular-nums text-zap-ink">{totalCreators.toLocaleString()}</span>{" "}
                  creator profiles on-chain{env.contractConfigured ? "" : " (connect a contract to count live)"}.
                </>
              ) : (
                <>Deploy once on testnet — share your /@handle and start receiving USDC.</>
              )}
            </p>
          </div>

          <div className="mt-10 flex flex-col items-center justify-center gap-4 sm:flex-row sm:flex-wrap">
            <button
              type="button"
              onClick={scrollToThreeWays}
              className="btn-ghost normal-case font-body tracking-normal"
            >
              Explore tips, unlocks &amp; ask
            </button>
            <Link
              to="/terminal"
              className="btn-primary inline-flex min-h-[48px] font-body items-center justify-center px-8 no-underline normal-case tracking-normal"
            >
              Open Terminal
            </Link>
          </div>
        </ScrollReveal>
      </div>
    </section>
  );
};

export default CTASection;
