import React, { useCallback, useEffect, useState } from "react";
import { motion } from "framer-motion";
import { Link, useNavigate } from "react-router-dom";

import Avatar from "@/components/primitives/Avatar";
import Skeleton from "@/components/primitives/Skeleton";
import ErrorState from "@/components/feedback/ErrorState";
import ScrollReveal from "@/components/feedback/ScrollReveal";
import { categorizeError } from "@/utils/error";
import { useOpenWalletConnect } from "@/components/wallet/WalletConnectModal";
import {
  NETWORK_EMPTY_BOARD_BODY,
  NETWORK_EMPTY_BOARD_EYEBROW,
  NETWORK_EMPTY_BOARD_TITLE,
  networkSharePagePath,
} from "@/content/networkBoardEmpty";
import { env } from "@/config/env";
import { useContract, useWallet } from "@/hooks";
import { useProfileStore } from "@/state/profileStore";
import type { NetworkEntry } from "@/types/contract";
import { formatNetworkEarningsUsdc } from "@/utils/format";

function displayNameFromUsername(username: string): string {
  return username
    .replace(/[_-]+/g, " ")
    .replace(/\b\w/g, (c) => c.toUpperCase());
}

function rankLabel(rank: number): { label: string; className: string } {
  if (rank === 1) {
    return { label: "◆ 01", className: "text-zap-gold" };
  }
  if (rank === 2 || rank === 3) {
    return {
      label: `0${rank}`,
      className: "text-zap-ink-muted",
    };
  }
  return {
    label: String(rank).padStart(2, "0"),
    className: "text-zap-ink-faint",
  };
}

export default function TopCreatorsSection() {
  const [creators, setCreators] = useState<NetworkEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const profile = useProfileStore((s) => s.profile);
  const isRegistered = useProfileStore((s) => s.isRegistered);
  const { getNetwork } = useContract();
  const { connected } = useWallet();
  const openWalletConnect = useOpenWalletConnect();
  const navigate = useNavigate();

  const load = useCallback(() => {
    if (!env.contractConfigured) {
      setLoading(false);
      setCreators([]);
      setError(null);
      return;
    }
    setLoading(true);
    setError(null);
    getNetwork(6)
      .then((data) => {
        setCreators(data);
        setLoading(false);
      })
      .catch(() => {
        setError("RPC_FETCH_FAILED");
        setLoading(false);
      });
  }, [getNetwork]);

  useEffect(() => {
    load();
  }, [load]);

  const handleRetry = useCallback(() => {
    load();
  }, [load]);

  const handleZap = useCallback(
    (username: string) => {
      if (!connected) {
        openWalletConnect();
        return;
      }
      navigate(`/@${username}`);
    },
    [connected, openWalletConnect, navigate],
  );

  return (
    <section id="example-creators" className="editorial-section bg-zap-bg">
      <div className="editorial-container">
        <ScrollReveal>
          <div className="mx-auto max-w-4xl text-center">
            <p className="mb-3 font-body text-xs font-semibold uppercase tracking-[0.12em] text-zap-accent">
              Live on-chain
            </p>
            <h2 className="font-body text-[clamp(2.25rem,5.5vw,3.75rem)] font-normal leading-[1.05] text-zap-ink">
              Example creators on Zap402
            </h2>
            <p className="mx-auto mt-6 max-w-xl font-body text-[15px] leading-relaxed text-zap-ink-muted">
              Live rows from the Soroban contract — tip volume shown in USDC-style amounts.
            </p>
        
          </div>
        </ScrollReveal>

        <div className="mt-14">
          {loading ? (
            <div data-testid="top-creators-loading-grid" aria-busy="true" aria-live="polite">
              <p className="mb-8 text-center font-body text-[13px] leading-relaxed text-zap-ink-muted">
                Loading top earners by zap volume. Pulling live rows from the Zap402 Soroban contract…
              </p>
              <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-3">
                {Array.from({ length: 6 }).map((_, i) => (
                  <div
                    key={i}
                    data-testid="top-creator-skeleton-card"
                    className="card-editorial p-6"
                  >
                    <div className="flex items-start gap-3">
                      <Skeleton variant="circle" height="48px" width="48px" />
                      <div className="min-w-0 flex-1 space-y-2">
                        <Skeleton variant="rect" height="14px" width="70%" />
                        <Skeleton variant="rect" height="12px" width="40%" />
                      </div>
                    </div>
                    <div
                      className="my-4 h-px w-full"
                      style={{ backgroundColor: "var(--color-border)" }}
                    />
                    <div className="grid grid-cols-2 gap-4">
                      <Skeleton variant="rect" height="56px" />
                      <Skeleton variant="rect" height="56px" />
                    </div>
                    <Skeleton className="mt-5" variant="rect" height="44px" />
                  </div>
                ))}
              </div>
            </div>
          ) : error ? (
            <ErrorState
              category={categorizeError(error)}
              error={error}
              onRetry={handleRetry}
            />
          ) : creators.length === 0 ? (
            <div className="group mx-auto max-w-lg border border-zap-border bg-zap-bg-raised p-6 text-center transition-[border-color,background-color] duration-200 ease-out md:p-8 hover:border-zap-border-bright hover:bg-zap-bg-overlay">
              <p className="font-body text-[10px] uppercase tracking-[0.2em] text-zap-ink-muted">
                {NETWORK_EMPTY_BOARD_EYEBROW}
              </p>
              <h3 className="mt-2 font-body text-xl font-normal uppercase tracking-tight text-zap-ink md:text-4xl">
                {NETWORK_EMPTY_BOARD_TITLE}
              </h3>
              <p className="mx-auto mt-6 max-w-md font-body text-[13px] leading-[1.85] text-zap-ink-muted">
                {NETWORK_EMPTY_BOARD_BODY}
              </p>
              <div className="mt-8 flex flex-col items-center justify-center gap-3 sm:flex-row sm:flex-wrap">
                {connected ? (
                  <>
                    <Link
                      to={networkSharePagePath(profile?.username, isRegistered)}
                      className="btn-primary inline-flex w-full min-w-[200px] font-body max-w-xs justify-center no-underline sm:w-auto"
                    >
                      SHARE PAGE
                    </Link>
                    <Link
                      to="/terminal"
                      className="btn-ghost inline-flex w-full min-w-[200px] font-body max-w-xs justify-center no-underline sm:w-auto"
                    >
                      ACCESS TERMINAL
                    </Link>
                  </>
                ) : (
                  <button
                    type="button"
                    onClick={() => openWalletConnect()}
                    className="btn-ghost inline-flex w-full min-w-[200px] font-body max-w-xs justify-center sm:w-auto"
                  >
                    CONNECT WALLET
                  </button>
                )}
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-3">
              {creators.map((creator, index) => {
                const rankNum = index + 1;
                const rk = rankLabel(rankNum);
                return (
                  <motion.div
                    key={creator.address}
                    data-testid="top-creator-card"
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: "-40px" }}
                    transition={{
                      duration: 0.4,
                      ease: "easeOut",
                      delay: index * 0.08,
                    }}
                    className="card-editorial card-editorial--hover p-6"
                  >
                    <div className="relative flex items-start gap-3">
                      <Avatar
                        address={creator.address}
                        alt={creator.username}
                        fallback={creator.username}
                        size="md"
                      />
                      <div className="min-w-0 flex-1">
                        <p className="font-body text-[15px] font-normal text-zap-ink">
                          {displayNameFromUsername(creator.username)}
                        </p>
                        <p className="font-body text-sm text-zap-ink-muted">
                          @{creator.username}
                        </p>
                      </div>
                      <span
                        className={`absolute right-0 top-0 font-body text-[10px] uppercase tracking-[0.12em] ${rk.className}`}
                      >
                        {rk.label}
                      </span>
                    </div>

                    <div
                      className="my-4 h-px w-full"
                      style={{ backgroundColor: "var(--color-border)" }}
                    />

                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <p className="text-label-caps text-[11px]">
                          TOTAL EARNED
                        </p>
                        <p className="font-body mt-1 text-[22px] font-normal tabular-nums text-zap-accent">
                          {formatNetworkEarningsUsdc(
                            creator.totalTipsReceived,
                          )}
                        </p>
                      </div>
                      <div>
                        <p className="text-label-caps text-[11px]">Tip count</p>
                        <p className="font-body mt-1 text-[22px] font-normal tabular-nums text-zap-ink">
                          {creator.totalTipsCount != null
                            ? creator.totalTipsCount.toLocaleString()
                            : "—"}
                        </p>
                      </div>
                    </div>

                    {/* <button
                      type="button"
                      onClick={() => handleZap(creator.username)}
                      className="btn-ghost mt-5 w-full py-3"
                    >
                      ZAP {displayNameFromUsername(creator.username)}
                    </button> */}
                  </motion.div>
                );
              })}
            </div>
          )}
        </div>

        {!loading && !error && creators.length > 0 && (
          <div className="mt-12 flex flex-col items-center gap-4 text-center">
            <p className="font-mono text-xs uppercase tracking-[0.08em] text-zap-ink-muted">
              Soroban RPC · block-aligned
            </p>
            <Link
              to="/terminal"
              aria-label="Open Terminal for balances and activity"
              className="btn-primary inline-flex min-h-[48px] font-body items-center justify-center px-8 no-underline"
            >
              OPEN TERMINAL
            </Link>
          </div>
        )}
      </div>
    </section>
  );
}
